// js/pdfFormGenerator.js
//
// LGS/bursluluk/özel test cevap kağıtlarını PDF olarak üreten modül.
// optik_form_test.html'deki pdfFormGenerator.js bölümünden çıkarılmıştır
// (fontlariKaydet ... topluFormPdfOlustur), değiştirilmeden.
//
// Bağımlılıklar (index.html'de CDN <script> olarak yüklenmeli):
//   - jsPDF (window.jspdf.jsPDF)
//   - qrcodejs (window.QRCode kurucu fonksiyonu — DOM tabanlı QR üretici)
//
// `layout` parametresi LayoutEngine.layoutHesapla() çıktısıdır — bu dosya
// layoutEngine.js'in hiçbir fonksiyonunu çağırmaz, sadece layout/form/ogrenci
// veri nesnelerini okur.

const { jsPDF } = window.jspdf;

// UYUMLULUK KATMANI: bu dosya "QRCode.toDataURL(text, opts) -> Promise<dataUrl>"
// arayüzünü bekliyor (npm 'qrcode' paketinin API'si). O paketin CDN derlemesi
// versiyondan versiyona kırılabiliyor; onun yerine çok daha stabil olan
// qrcodejs'i (DOM tabanlı) kullanıp AYNI arayüzü taklit ediyoruz.
const QRCodeLibKurucu = window.QRCode; // qrcodejs'in kurucu fonksiyonu

const QRCode = {
  toDataURL: function (text, opts) {
    return new Promise(function (resolve, reject) {
      try {
        const boyut = (opts && opts.width) || 240;
        const kutu = document.createElement('div');
        kutu.style.display = 'none';
        document.body.appendChild(kutu);
        new QRCodeLibKurucu(kutu, { text: text, width: boyut, height: boyut, correctLevel: QRCodeLibKurucu.CorrectLevel.M });
        setTimeout(function () {
          const canvas = kutu.querySelector('canvas');
          const img = kutu.querySelector('img');
          const dataUrl = canvas ? canvas.toDataURL('image/png') : (img ? img.src : null);
          document.body.removeChild(kutu);
          if (dataUrl) resolve(dataUrl); else reject(new Error('QR kod oluşturulamadı'));
        }, 80);
      } catch (e) { reject(e); }
    });
  }
};

const POPPINS_REGULAR_BASE64 = "";

const POPPINS_BOLD_BASE64 = "";

/** Poppins fontlarını jsPDF'e bir kere kaydeder (VFS + addFont). */
// Renk paleti (RGB üçlüleri — doc.setFillColor(...RENK) gibi spread edilerek kullanılıyor).
const ANA_RENK = [194, 24, 91];      // koyu pembe/bordo — başlık şeridi, çerçeveler, vurgu metinleri
const BEYAZ = [255, 255, 255];
const KOYU_METIN = [33, 33, 33];
const ACIK_RENK = [252, 228, 236];   // açık pembe — ders başlığı zemin rengi
const ZEBRA_ACIK = [253, 245, 248];  // çok açık pembe — etiket/değer kutularının zemin rengi

let fontlarYuklendiMi = false;
function fontlariKaydet(doc) {
  if (fontlarYuklendiMi) return;
  doc.addFileToVFS('Poppins-Regular.ttf', POPPINS_REGULAR_BASE64);
  doc.addFont('Poppins-Regular.ttf', 'Poppins', 'normal');
  doc.addFileToVFS('Poppins-Bold.ttf', POPPINS_BOLD_BASE64);
  doc.addFont('Poppins-Bold.ttf', 'Poppins', 'bold');
  fontlarYuklendiMi = true;
}

/** Cap-height yaklaşık hesaplaması (mm), baseline konumlandırma için. */
function capYuksekligi(fontPt) {
  return fontPt * 0.3528 * 0.72;
}

/** Bir bandın üstünden itibaren, dikey ortalanmış tek satır metin baseline'ı. */
function baselineUst(yUst, yukseklik, fontPt, altPay = null) {
  if (altPay !== null) return yUst + yukseklik - altPay;
  return yUst + (yukseklik + capYuksekligi(fontPt)) / 2;
}

function dikdortgenCiz(doc, x, y, w, h, renk) {
  doc.setFillColor(...renk);
  doc.rect(x, y, w, h, 'F');
}

function cerceveCiz(doc, x, y, w, h, renk, kalinlik = 0.3) {
  doc.setDrawColor(...renk);
  doc.setLineWidth(kalinlik);
  doc.rect(x, y, w, h, 'S');
}

/**
 * Etiket (üstte, küçük, renkli) + değer (altta, büyük, koyu) kutusu çizer.
 * Boyutlar mm; font boyutları kutunun yüksekliğine ORANLA otomatik ölçeklenir
 * (dinamik testlerin çok küçük mini-formlarında da okunaklı kalması için).
 */
/**
 * Türkçe kurallarına göre büyük harfe çevirir (JS'in standart
 * toUpperCase()'i "i" harfini yanlış "I" yapar; Türkçe'de "İ" olmalı).
 * Optik formlarda öğrenci adı/sınıf/sınav adı gibi alanlar büyük harfle
 * basılsın istendiği için (bkz. etiketDegerKutusu) kullanılıyor.
 */
function buyukHarfTR(metin) {
  return String(metin == null ? '' : metin).toLocaleUpperCase('tr-TR');
}

function etiketDegerKutusu(doc, box, etiket, deger, opts = {}) {
  const { etiketOran = 0.542, degerOran = 0.833, minEtiketPt = 3.2, minDegerPt = 4.5 } = opts;
  const etiketPt = Math.max(minEtiketPt, box.height * etiketOran);
  const degerPt = Math.max(minDegerPt, box.height * degerOran);

  cerceveCiz(doc, box.x, box.y, box.width, box.height, ANA_RENK, 0.35);

  doc.setFont('Poppins', 'bold');
  doc.setFontSize(etiketPt);
  doc.setTextColor(...ANA_RENK);
  doc.text(etiket, box.x + box.width * 0.03, baselineUst(box.y, box.height, etiketPt, box.height * 0.62));

  doc.setFont('Poppins', 'normal');
  doc.setFontSize(degerPt);
  doc.setTextColor(...KOYU_METIN);
  doc.text(buyukHarfTR(deger), box.x + box.width * 0.03, baselineUst(box.y, box.height, degerPt, box.height * 0.14));
}

/** Kitapçık Türü rozetini (dolgu renkli, dikkat çekici) çizer. */
function kitapcikTuruRozeti(doc, box, deger) {
  dikdortgenCiz(doc, box.x, box.y, box.width, box.height, ANA_RENK);
  doc.setFont('Poppins', 'bold');
  doc.setFontSize(Math.max(3, box.height * 0.32));
  doc.setTextColor(...BEYAZ);
  doc.text('KİTAPÇIK TÜRÜ', box.x + box.width * 0.05, baselineUst(box.y, box.height, box.height * 0.32, box.height * 0.66));
  doc.setFontSize(Math.max(5, box.height * 0.62));
  doc.text(String(deger), box.x + box.width * 0.78, baselineUst(box.y, box.height, box.height * 0.62, box.height * 0.16), { align: 'center' });
}

/** Tek bir baloncuğu çizer.
 * Dolu ise: siyah zemin, rakam basılmaz (OMR okuyucunun güveni artar).
 * Boş ise: kırmızı/bordo kenarlık + küçük rakam etiketi. */
function kucukBaloncukCiz(doc, cx, cy, r, etiket, dolu) {
  doc.setLineWidth(0.3);
  if (dolu) {
    // Tamamen siyah dolu — OMR için maksimum kontrast
    doc.setFillColor(0, 0, 0);
    doc.setDrawColor(0, 0, 0);
    doc.circle(cx, cy, r, 'FD');
    // Rakam basılmıyor: siyah zemin üstünde zaten okunamaz,
    // OMR motoru da sadece koyuluğa bakıyor.
  } else {
    doc.setDrawColor(...ANA_RENK);
    doc.circle(cx, cy, r, 'S');
    doc.setTextColor(...KOYU_METIN);
    doc.setFont('Poppins', 'normal');
    doc.setFontSize(Math.max(2.5, r * 1.9));
    doc.text(String(etiket), cx, cy + r * 0.35, { align: 'center' });
  }
}

/**
 * Kitapçık Türü baloncuk bloğunu çizer. `kitapcikTuru` verilirse (PDF belirli
 * bir öğrenci için üretiliyorsa) doğru harf otomatik olarak DOLU basılır —
 * öğrencinin bunu ayrıca işaretlemesine gerek kalmaz, okuma da daha güvenilir
 * olur.
 */
function kitapcikAlaniCiz(doc, kitapcikAlani, kitapcikTuru) {
  doc.setFont('Poppins', 'bold');
  doc.setFontSize(6.5);
  doc.setTextColor(...ANA_RENK);
  doc.text('K', kitapcikAlani.x + kitapcikAlani.genislik / 2, kitapcikAlani.y + kitapcikAlani.baslikYukseklik * 0.85, { align: 'center' });
  for (const secenek of kitapcikAlani.secenekler) {
    const dolu = kitapcikTuru && String(kitapcikTuru).toUpperCase() === secenek.harf;
    kucukBaloncukCiz(doc, secenek.cx, secenek.cy, secenek.r, secenek.harf, dolu);
  }
}

/**
 * Numara (öğrenci no) baloncuk ızgarasını çizer. `ogrenciNo` verilirse, her
 * basamağın doğru rakamı otomatik olarak DOLU basılır (bkz. kitapcikAlaniCiz
 * ile aynı gerekçe). QR kodunun YERİNİ alıyor — bkz. layoutEngine.js'teki
 * numaraAlaniHesapla notu.
 */
function numaraAlaniCiz(doc, numaraAlani, ogrenciNo) {
  const basamaklar = String(ogrenciNo || '').replace(/\D/g, '').padStart(numaraAlani.basamakSayisi, ' ').slice(-numaraAlani.basamakSayisi);

  doc.setFont('Poppins', 'bold');
  doc.setFontSize(6.5);
  doc.setTextColor(...ANA_RENK);
  doc.text('NUMARA', numaraAlani.x + numaraAlani.width / 2, numaraAlani.y + numaraAlani.baslikYukseklik * 0.85, { align: 'center' });

  numaraAlani.basamaklar.forEach((basamak, i) => {
    const hedefRakam = basamaklar[i] !== ' ' ? basamaklar[i] : null;
    for (const bubble of basamak.bubbles) {
      const dolu = hedefRakam !== null && String(bubble.deger) === hedefRakam;
      kucukBaloncukCiz(doc, bubble.cx, bubble.cy, bubble.r, bubble.deger, dolu);
    }
  });
}

/**
 * Form Kodu baloncuk bloğunu çizer. Öğrenciyle/kitapçıkla İLGİSİ YOK —
 * kağıdın HANGİ optik form şablonuyla (LGS/Bursluluk/Özel) üretildiğini
 * OMR ile doğrulamak için, `sinavTuru`ya karşılık gelen SABİT harf her
 * zaman otomatik DOLU basılır (bkz. layoutEngine.js: FORM_KODU_HARFLERI,
 * omrEngine.js: formKoduOku). Amaç: seçili sınavdan farklı bir optik
 * form kağıdının yanlışlıkla okunmasını engellemek.
 */
function formKoduAlaniCiz(doc, formKoduAlani, sinavTuru) {
  const hedefHarf = window.LayoutEngine.formKoduHarfiGetir(sinavTuru);
  doc.setFont('Poppins', 'bold');
  doc.setFontSize(6.5);
  doc.setTextColor(...ANA_RENK);
  doc.text('F', formKoduAlani.x + formKoduAlani.genislik / 2, formKoduAlani.y + formKoduAlani.baslikYukseklik * 0.85, { align: 'center' });
  for (const secenek of formKoduAlani.secenekler) {
    const dolu = secenek.harf === hedefHarf;
    kucukBaloncukCiz(doc, secenek.cx, secenek.cy, secenek.r, secenek.harf, dolu);
  }
}

/** Ortak header'ı (Ad Soyad / Öğrenci No / Sınıf / Kitapçık Türü / Sınav Adı) çizer. */
async function headerCiz(doc, form, ogrenci, sinavTuru) {
  const b = form.baslikAlani;
  cerceveCiz(doc, b.x, b.y, b.width, b.height, ANA_RENK, 0.5);
  doc.setFont('Poppins', 'bold');
  const baslikPt = Math.max(6, b.height * 1.05);
  doc.setFontSize(baslikPt);
  doc.setTextColor(...ANA_RENK);
  doc.text(form.baslikMetni || 'CEVAP KAĞIDI', b.x + b.width / 2, baselineUst(b.y, b.height, baslikPt, b.height * 0.14), { align: 'center' });

  etiketDegerKutusu(doc, form.adSoyadAlani, 'AD SOYAD', ogrenci.adSoyad || '');

  if (form.bilgiSatiri) {
    etiketDegerKutusu(doc, form.bilgiSatiri.ogrenciNoAlani, 'ÖĞRENCİ NO', ogrenci.ogrenciNo || '');
    etiketDegerKutusu(doc, form.bilgiSatiri.sinifAlani, 'SINIF', ogrenci.sinif || '');
  }

  if (form.sinavAdiAlani) {
    etiketDegerKutusu(doc, form.sinavAdiAlani, 'SINAV ADI', ogrenci.sinavAdi || '');
  }

  if (form.kitapcikAlani) {
    kitapcikAlaniCiz(doc, form.kitapcikAlani, ogrenci.kitapcikTuru || null);
  }

  if (form.numaraAlani) {
    numaraAlaniCiz(doc, form.numaraAlani, ogrenci.ogrenciNo);
  }

  if (form.formKoduAlani) {
    formKoduAlaniCiz(doc, form.formKoduAlani, sinavTuru);
  }
}

/** Bir baloncuğu (daire + harf) çizer. */
function baloncukCiz(doc, sik) {
  doc.setDrawColor(...ANA_RENK);
  doc.setLineWidth(0.35);
  doc.circle(sik.cx, sik.cy, sik.r, 'S');
  doc.setFont('Poppins', 'normal');
  doc.setFontSize(Math.max(3, sik.r * 2.2));
  doc.setTextColor(...KOYU_METIN);
  doc.text(sik.harf, sik.cx, sik.cy + sik.r * 0.35, { align: 'center' });
}

/** LGS/bursluluk gibi "bölüm > ders sütunu" yapısındaki formları çizer. */
function bolumlerCiz(doc, form) {
  for (const bolum of form.bolumler) {
    const dersler = bolum.dersSutunlari;
    const maxYukseklik = Math.max(...dersler.map((d) => d.toplamYukseklik));
    const grupAltY = dersler[0].y + maxYukseklik;

    if (bolum.baslik) {
      cerceveCiz(doc, bolum.x, bolum.baslikY, bolum.genislik, bolum.baslikYukseklik, ANA_RENK, 0.5);
      doc.setFont('Poppins', 'bold');
      const pt = 9;
      doc.setFontSize(pt);
      doc.setTextColor(...ANA_RENK);
      doc.text(bolum.baslik, bolum.x + bolum.genislik / 2, baselineUst(bolum.baslikY, bolum.baslikYukseklik, pt, 2.2), { align: 'center' });
    }

    cerceveCiz(doc, bolum.x, dersler[0].y, bolum.genislik, grupAltY - dersler[0].y + 2, ANA_RENK, 0.4);

    for (const ders of dersler) {
      const colCenter = ders.x + ders.width / 2;

      cerceveCiz(doc, ders.x, ders.y, ders.width, ders.baslikYuksekligi, ANA_RENK, 0.3);
      doc.setFont('Poppins', 'bold');
      doc.setFontSize(6.4);
      doc.setTextColor(...KOYU_METIN);
      const satirlar = ders.dersAdiSatirlari;
      const satirH = 3.6;
      const toplamH = satirlar.length * satirH;
      const ilkY = ders.y + (ders.baslikYuksekligi - toplamH) / 2 + satirH * 0.75;
      satirlar.forEach((satir, i) => {
        doc.text(satir, colCenter, ilkY + i * satirH, { align: 'center' });
      });

      for (const soru of ders.sorular) {
        doc.setFont('Poppins', 'normal');
        doc.setFontSize(6.5);
        doc.setTextColor(...KOYU_METIN);
        doc.text(String(soru.soruNo), soru.etiketX, soru.etiketY, { align: 'center' });
        for (const sik of soru.sikler) baloncukCiz(doc, sik);
      }
    }
  }

  // NOT: genelIzgaraCercevesiCiz() KASITLI OLARAK ARTIK ÇAĞRILMIYOR.
  // Bu fonksiyonun çizdiği ızgara-çerçevesi köşe kareleri, sayfanın kendi
  // hizalama işaretlerine (özellikle sağ tarafta, QR/Fen Bilimleri'ne
  // yakın) çok benziyor ve otomatik OMR tespiti ikisini karıştırabiliyor
  // (gözlemlenen hata: sağ-üst/sağ-alt köşeler yanlış bulunuyordu). Okuma
  // tarafında zaten SADECE sayfa-köşesi homografisi (bu çerçeve köşeleri
  // OLMADAN) yeterli hassasiyeti sağladığından, bu çizim güvenle
  // kaldırıldı — bkz. omrEngine.js'deki formuOku/formuOkuElleKoseli.
  // genelIzgaraCercevesiCiz(doc, form);
}

/**
 * Dinamik "özel test" formlarını çizer: sayfada BİRDEN FAZLA mini-form
 * olabilir, her biri düz (ders grubu olmayan) bir soru ızgarasına sahiptir.
 *
 * KRİTİK: zebra bantları, o mini-formun TÜM baloncuklarından önce, satır
 * indeksine göre (blok sayısından bağımsız) TEK SEFERDE çizilir.
 */
function izgaraCiz(doc, form) {
  const izgara = form.izgara;

  for (const soru of izgara.sorular) {
    doc.setFont('Poppins', 'normal');
    doc.setFontSize(Math.max(4, izgara.baloncukCap * 1.1));
    doc.setTextColor(...KOYU_METIN);
    doc.text(String(soru.soruNo), soru.etiketX, soru.etiketY, { align: 'center' });
    for (const sik of soru.sikler) baloncukCiz(doc, sik);
  }

  // Kesim kılavuzu (kesikli çerçeve)
  doc.setDrawColor(153, 153, 153);
  doc.setLineDashPattern([1, 1], 0);
  doc.setLineWidth(0.25);
  doc.rect(form.bolge.x, form.bolge.y, form.bolge.width, form.bolge.height, 'S');
  doc.setLineDashPattern([], 0);
}

function hizalamaIsaretleriCiz(doc, form) {
  doc.setFillColor(0, 0, 0);
  for (const m of form.hizalamaIsaretleri) {
    doc.rect(m.x, m.y, m.boyut, m.boyut, 'F');
  }
}

/**
 * TÜM ders sütunlarını (sözel + sayısal) SARAN tek, KALIN siyah çerçeve +
 * onun 4 köşesine dolu hizalama kareleri çizer. Sütun bazlı (her ders için
 * ayrı) çerçeve/köşe yaklaşımının YERİNE geçti (bkz. genelIzgaraCercevesiHesapla
 * içindeki gerekçe): sütunlar arası dar boşuk yüzünden köşeler birbirine
 * karışıyordu; tek, büyük, izole bir çerçeve bu riski ortadan kaldırıyor.
 */
function genelIzgaraCercevesiCiz(doc, form) {
  const gc = form.genelIzgaraCercevesi;
  if (!gc) return;

  doc.setDrawColor(0, 0, 0);
  doc.setLineWidth(0.8); // KALIN çizgi — istenen görsel
  doc.rect(gc.kutu.x, gc.kutu.y, gc.kutu.width, gc.kutu.height, 'S');

  const b = gc.koseBoyut;
  const yarim = b / 2;
  doc.setFillColor(0, 0, 0);
  for (const nokta of Object.values(gc.koseler)) {
    doc.rect(nokta.x - yarim, nokta.y - yarim, b, b, 'F');
  }
}

/**
 * Ana giriş noktası. `layout`, layoutEngine.js'in layoutHesapla() çıktısıdır.
 * `ogrenci` her form/sayfa için aynı bilgileri taşır (tek öğrenci basımı);
 * toplu basım için bu fonksiyonu her öğrenci için ayrı çağırıp sayfaları
 * birleştirin (bkz. dosya sonundaki `topluFormPdfOlustur`).
 *
 * @returns {Promise<jsPDF>} doc nesnesi — .save('dosya.pdf') veya .output('blob') ile kullanılır
 */
async function formPdfOlustur(layout, ogrenci = {}) {
  const doc = new jsPDF({ unit: 'mm', format: [layout.sayfaBoyutu.width, layout.sayfaBoyutu.height] });
  fontlariKaydet(doc);

  for (const form of layout.formlar) {
    hizalamaIsaretleriCiz(doc, form);
    await headerCiz(doc, form, ogrenci, layout.sinavTuru);

    if (form.bolumler) {
      bolumlerCiz(doc, form);
    } else if (form.izgara) {
      izgaraCiz(doc, form);
    }
  }

  return doc;
}

/**
 * Bir sınıftaki TÜM öğrenciler için tek bir PDF üretir (her öğrenci kendi
 * sayfasında/sayfalarında). Dinamik "özel test" + çoklu-form-per-A4 durumunda
 * her öğrenci hâlâ ayrı bir A4 alır (yani 6'lı düzen "6 farklı öğrenci aynı
 * kağıtta" değil, "aynı öğrencinin kağıdı 6 kopya" anlamına gelir demektir —
 * bu varsayımı ders/sınav akışınıza göre gözden geçirmeniz gerekebilir).
 */
async function topluFormPdfOlustur(layout, ogrenciListesi) {
  const doc = new jsPDF({ unit: 'mm', format: [layout.sayfaBoyutu.width, layout.sayfaBoyutu.height] });
  fontlariKaydet(doc);

  for (let i = 0; i < ogrenciListesi.length; i++) {
    if (i > 0) doc.addPage([layout.sayfaBoyutu.width, layout.sayfaBoyutu.height]);
    const ogrenci = ogrenciListesi[i];
    for (const form of layout.formlar) {
      hizalamaIsaretleriCiz(doc, form);
      await headerCiz(doc, form, ogrenci, layout.sinavTuru);
      if (form.bolumler) {
        bolumlerCiz(doc, form);
      } else if (form.izgara) {
        izgaraCiz(doc, form);
      }
    }
  }

  return doc;
}

export { formPdfOlustur, topluFormPdfOlustur };
